from pathlib import Path
import base64
import sys

out_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else Path('assets/fighters')
out_dir.mkdir(parents=True, exist_ok=True)

ASSETS = {
    'islam-makhachev.webp': '''''' ,
    'islam-makhachev-thumb.webp': '''''',
}

for name, data in ASSETS.items():
    (out_dir / name).write_bytes(base64.b64decode(data))
